SELECT T2.type, T2.name, T.count_month, SUM( (COALESCE(day_1, 0) + COALESCE(day_2, 0) + COALESCE(day_3, 0) + COALESCE(day_4, 0) + COALESCE(day_5, 0) + COALESCE(day_6, 0) + COALESCE(day_7, 0) + COALESCE(day_8, 0) + COALESCE(day_9, 0) + COALESCE(day_10, 0) + COALESCE(day_11, 0) + COALESCE(day_12, 0) + COALESCE(day_13, 0) + COALESCE(day_14, 0) + COALESCE(day_15, 0) + COALESCE(day_16, 0) + COALESCE(day_17, 0) + COALESCE(day_18, 0) + COALESCE(day_19, 0) + COALESCE(day_20, 0) + COALESCE(day_21, 0) + COALESCE(day_22, 0) + COALESCE(day_23, 0) + COALESCE(day_24, 0) + COALESCE(day_25, 0) + COALESCE(day_26, 0) + COALESCE(day_27, 0) + COALESCE(day_28, 0) + COALESCE(day_29, 0) + COALESCE(day_30, 0) + COALESCE(day_31, 0) )) as total FROM tb_account_tally_sheet T JOIN tb_account_mapping T2 ON T2.type = T.type AND IFNULL(T2.del_yn, 'N') = 'N' WHERE T.count_year = #{year}
AND count_month = #{month}
GROUP BY T2.type, T2.name, T.count_month ORDER BY T2.type ASC
LIMIT ${limit}

SELECT T.account_id, A.account_name, T2.type, T2.name, T.count_month, SUM( (COALESCE(day_1, 0) + COALESCE(day_2, 0) + COALESCE(day_3, 0) + COALESCE(day_4, 0) + COALESCE(day_5, 0) + COALESCE(day_6, 0) + COALESCE(day_7, 0) + COALESCE(day_8, 0) + COALESCE(day_9, 0) + COALESCE(day_10, 0) + COALESCE(day_11, 0) + COALESCE(day_12, 0) + COALESCE(day_13, 0) + COALESCE(day_14, 0) + COALESCE(day_15, 0) + COALESCE(day_16, 0) + COALESCE(day_17, 0) + COALESCE(day_18, 0) + COALESCE(day_19, 0) + COALESCE(day_20, 0) + COALESCE(day_21, 0) + COALESCE(day_22, 0) + COALESCE(day_23, 0) + COALESCE(day_24, 0) + COALESCE(day_25, 0) + COALESCE(day_26, 0) + COALESCE(day_27, 0) + COALESCE(day_28, 0) + COALESCE(day_29, 0) + COALESCE(day_30, 0) + COALESCE(day_31, 0) )) AS total FROM tb_account_tally_sheet T JOIN tb_account_mapping T2 ON T2.type = T.type LEFT OUTER JOIN tb_account A ON A.account_id = T.account_id WHERE T.count_year = #{year}
AND T.count_month = #{month}
AND T2.type = #{type}
AND T2.name = #{name}
GROUP BY T.account_id, A.account_name, T2.type, T2.name, T.count_month ORDER BY A.account_name, T.account_id

mapper.insert:
INSERT INTO tb_headoffice_electronic_payment
payment_id, draft_dt, start_dt, doc_type, department, status, retention_dt, access_level, user_id, charge_sign, tm_user, tm_sign, payer_user, payer_sign, ceo_user, ceo_sign, reg_dt, reg_user_id
VALUES
#{payment_id}, COALESCE( STR_TO_DATE(#{draft_dt}, '%Y-%m-%d %H:%i:%s'), STR_TO_DATE(#{draft_dt}, '%Y-%m-%d %H:%i') ), COALESCE( STR_TO_DATE(#{start_dt}, '%Y-%m-%d %H:%i:%s'), STR_TO_DATE(#{start_dt}, '%Y-%m-%d %H:%i'), STR_TO_DATE(#{draft_dt}, '%Y-%m-%d %H:%i:%s'), STR_TO_DATE(#{draft_dt}, '%Y-%m-%d %H:%i') ), #{doc_type}, #{department}, #{status}, #{retention_dt}, #{access_level}, #{user_id}, #{charge_sign}, #{tm_user}, #{tm_sign}, #{payer_user}, #{payer_sign}, #{ceo_user}, #{ceo_sign}, CONVERT_TZ(NOW(), '+00:00', '+09:00'), #{user_id}
ON DUPLICATE KEY UPDATE
draft_dt = COALESCE( STR_TO_DATE(#{draft_dt}, '%Y-%m-%d %H:%i:%s'), STR_TO_DATE(#{draft_dt}, '%Y-%m-%d %H:%i') ), start_dt = COALESCE( STR_TO_DATE(#{start_dt}, '%Y-%m-%d %H:%i:%s'), STR_TO_DATE(#{start_dt}, '%Y-%m-%d %H:%i'), STR_TO_DATE(#{draft_dt}, '%Y-%m-%d %H:%i:%s'), STR_TO_DATE(#{draft_dt}, '%Y-%m-%d %H:%i') ), doc_type = #{doc_type}, department = #{department}, status = #{status}, retention_dt = #{retention_dt}, access_level = #{access_level}, user_id= #{user_id}, charge_sign = #{charge_sign}, tm_user = #{tm_user}, tm_sign = #{tm_sign}, payer_user = #{payer_user}, payer_sign = #{payer_sign}, ceo_user = #{ceo_user}, ceo_sign = #{ceo_sign}

mapper.update:
UPDATE tb_headoffice_purchase_request pr
JOIN tb_headoffice_electronic_payment ep
  ON ep.payment_id = pr.payment_id
SET pr.buy_yn = #{buy_yn}
WHERE pr.payment_id = #{payment_id}
  AND pr.idx = #{idx}
  AND ep.payer_user = #{user_id}
  AND IFNULL(ep.payer_sign, '') != '4'

mapper.select:

SELECT payment_id,
	   image_path,
	   image_order,
	   image_name
FROM tb_electronic_payment_file_management
WHERE payment_id = #{payment_id}


  		AND EXISTS (
  			SELECT 1
  			FROM tb_headoffice_electronic_payment ep
  			JOIN tb_user lu
  			  ON lu.user_id = #{user_id}
  			 AND IFNULL(lu.del_yn, 'N') = 'N'
  			WHERE ep.payment_id = #{payment_id}
  			  AND (
  			  	lu.position = 0
  			  	OR ep.reg_user_id = #{user_id}
  			  	OR ep.tm_user = #{user_id}
  			  	OR ep.ceo_user = #{user_id}
  			  	OR ep.payer_user = #{user_id}
  			  	OR (lu.position = 1 AND lu.department = ep.department)
  			  	OR (
  			  		#{user_id} = 'iy1'
  			  		AND EXISTS (
  			  			SELECT 1
  			  			FROM tb_headoffice_purchase_request prx
  			  			WHERE prx.payment_id = ep.payment_id
  			  		)
  			  	)
  			  )
  		)


  		AND 1 = 0


ORDER BY image_order ASC

