INSERT INTO tb_headoffice_purchase_request
idx, payment_id, item_name, qty, price, use_note, use_name, link, note, buy_yn, payment_note
VALUES
#{idx}, #{payment_id}, #{item_name}, #{qty}, #{price}, #{use_note}, #{use_name}, #{link}, #{note}, #{buy_yn}, #{payment_note}
ON DUPLICATE KEY UPDATE
payment_id = #{payment_id}, item_name = #{item_name}, qty = #{qty}, price = #{price}, use_note = #{use_note}, use_name = #{use_name}, link = #{link}, note = #{note}, buy_yn = #{buy_yn}, payment_note = #{payment_note}

