UPDATE tb_hr_evaluation_type
SET del_yn = 'Y'
WHERE doc_id = #{doc_id}

mapper.select:
SELECT e.idx, e.user_id, u.user_name, u.position, u.department, e.doc_type, t.doc_name, t.approval_position, DATE_FORMAT(e.start_time, '%Y-%m-%d') AS start_time, DATE_FORMAT(e.end_time, '%Y-%m-%d') AS end_time, (SELECT COUNT(*) FROM tb_hr_evaluation_kpi k WHERE k.document_id = e.document_id) AS kpi_count, e.tm_user, e.tm_sign, DATE_FORMAT(e.tm_dt, '%Y-%m-%d %H:%i:%s') AS tm_dt, e.hp_sign, DATE_FORMAT(e.hp_dt, '%Y-%m-%d %H:%i:%s') AS hp_dt, e.hr_user, e.hr_sign, DATE_FORMAT(e.hr_dt, '%Y-%m-%d %H:%i:%s') AS hr_dt, e.ceo_user, e.ceo_sign, DATE_FORMAT(e.ceo_dt, '%Y-%m-%d %H:%i:%s') AS ceo_dt, (SELECT COUNT(*) FROM tb_hr_evaluation_file f WHERE f.notice_idx = e.idx) AS file_cnt, DATE_FORMAT(e.reg_dt, '%Y-%m-%d %H:%i:%s') AS reg_dt, e.document_id FROM tb_hr_evaluation e JOIN tb_user u ON u.user_id = e.user_id LEFT JOIN tb_hr_evaluation_type t ON t.doc_type = e.doc_type AND DATE(t.start_time) = DATE(e.start_time) AND DATE(t.end_time) = DATE(e.end_time) AND t.del_yn = 'N' WHERE e.del_yn = 'N'
AND e.user_id = #{user_id}
AND FIND_IN_SET(u.department, #{departments}) > 0
AND u.department = #{department}
ORDER BY e.idx DESC

